import { WishlistItem } from "@/types/secret-santa";

type Props = {
  youAreInRoom: boolean;
  alreadyStarted: boolean;
  assignmentName?: string;
  ownerWishlist?: WishlistItem[];
  ownerName?: string;
  claimedItemId?: string;
  onClaim?: (id: string) => void;
  isOwner?: boolean;
};

export default function AssignmentPanel({
  youAreInRoom,
  alreadyStarted,
  assignmentName,
  ownerWishlist,
  ownerName,
  claimedItemId,
  onClaim,
  isOwner,
}: Props) {
  if (!youAreInRoom) {
    return null;
  }

  // For birthday: show owner's wishlist for claiming
  if (ownerWishlist && ownerName && !isOwner) {
    return (
      <div className="birthday-card confetti-fade px-6 py-6">
        <p className="text-xs uppercase text-pink-600 font-bold text-center">Что подарить {ownerName}?</p>
        {!alreadyStarted && (
          <p className="mt-2 text-center text-xs font-medium text-slate-500">
            Выбор подарков откроется после старта праздника владельцем комнаты.
          </p>
        )}
        <div className="mt-4 space-y-2">
          {ownerWishlist.length === 0 && (
            <p className="text-sm italic text-slate-400">Список пока пуст...</p>
          )}
          {ownerWishlist.map((item) => {
            const isClaimedByMe = item.id === claimedItemId;
            const isClaimedByOthers = item.claimedBy && !isClaimedByMe;

            return (
              <div 
                key={item.id}
                className={`flex items-center justify-between p-3 rounded-xl border-2 transition ${
                  isClaimedByMe ? "border-pink-400 bg-pink-50" : "border-slate-100"
                }`}
              >
                <span className={`text-sm font-medium ${
                  isClaimedByOthers ? "line-through text-slate-300" : "text-slate-700"
                }`}>
                  {item.text}
                </span>
                {!isClaimedByOthers && !claimedItemId && onClaim && alreadyStarted && (
                  <button
                    onClick={() => onClaim(item.id)}
                    className="text-xs font-black text-pink-600 uppercase hover:text-pink-800"
                  >
                    Выбрать
                  </button>
                )}
                {isClaimedByMe && (
                  <span className="text-[10px] font-black text-pink-600 uppercase">Выбрано вами</span>
                )}
                {isClaimedByOthers && (
                  <span className="text-[10px] font-bold text-slate-300 uppercase">Занято</span>
                )}
              </div>
            );
          })}
        </div>
      </div>
    );
  }

  // For owner or if no ownerWishlist, show nothing after started
  if (alreadyStarted) {
    return null;
  }

  // Original Secret Santa logic (not used in birthday)
  return (
    <div className="birthday-card confetti-fade px-6 py-6 text-center">
      <p className="text-xs uppercase text-pink-600 font-bold">Вы готовите сюрприз для</p>
      {!alreadyStarted && (
        <p className="mt-3 text-lg font-semibold text-slate-800">
          Скоро узнаем, чьи желания вам достались! 
        </p>
      )}
      {alreadyStarted && assignmentName && (
        <>
          <p className="mt-4 text-sm text-slate-600 font-medium">Именинник:</p>
          <p className="text-4xl font-black text-pink-600">{assignmentName}</p>
          <p className="mt-2 text-sm text-slate-600">
            Тссс! Это сюрприз, список видите только вы.
          </p>
          <div className="mt-6 text-left">
            <p className="text-xs uppercase tracking-[0.3em] text-cyan-400 font-bold">
              Список желаний:
            </p>
            {/* assignedWishlist removed */}
          </div>
        </>
      )}
      {alreadyStarted && !assignmentName && (
        <p className="mt-4 text-lg font-semibold text-slate-500">
          Мы обновляем данные, подождите секунду...
        </p>
      )}
    </div>
  );
}

import { WishlistItem } from "@/types/happy-birthday";

type Props = {
  youAreInRoom: boolean;
  alreadyStarted: boolean;
  assignmentName?: string;
  ownerWishlist?: WishlistItem[];
  ownerName?: string;
  claimedItemId?: string;
  onClaim?: (id: string) => void;
  isOwner?: boolean;
};

export default function AssignmentPanel({
  youAreInRoom,
  alreadyStarted,
  assignmentName,
  ownerWishlist,
  ownerName,
  claimedItemId,
  onClaim,
  isOwner,
}: Props) {
  if (!youAreInRoom) {
    return null;
  }

  // For birthday: show owner's wishlist for claiming
  if (ownerWishlist && ownerName && !isOwner) {
    return (
      <div className="birthday-card confetti-fade px-6 py-6">
        <p className="text-xs uppercase text-pink-600 font-bold text-center">Что подарить {ownerName}?</p>
        {!alreadyStarted && (
          <p className="mt-2 text-center text-xs font-medium text-slate-500">
            Выбор подарков откроется после старта праздника владельцем комнаты.
          </p>
        )}
        <div className="mt-4 space-y-2">
          {ownerWishlist.length === 0 && (
            <p className="text-sm italic text-slate-400">Список пока пуст...</p>
          )}
          {ownerWishlist.map((item) => {
            const isClaimedByMe = item.id === claimedItemId;
            const isClaimedByOthers = item.claimedBy && !isClaimedByMe;

            return (
              <div 
                key={item.id}
                className={`flex items-center justify-between p-3 rounded-xl border-2 transition ${
                  isClaimedByMe ? "border-pink-400 bg-pink-50" : "border-slate-100"
                }`}
              >
                <span className={`text-sm font-medium ${
                  isClaimedByOthers ? "line-through text-slate-300" : "text-slate-700"
                }`}>
                  {item.text}
                </span>
                {!isClaimedByOthers && !claimedItemId && onClaim && alreadyStarted && (
                  <button
                    onClick={() => onClaim(item.id)}
                    className="text-xs font-black text-pink-600 uppercase hover:text-pink-800"
                  >
                    Выбрать
                  </button>
                )}
                {isClaimedByMe && (
                  <span className="text-[10px] font-black text-pink-600 uppercase">Выбрано вами</span>
                )}
                {isClaimedByOthers && (
                  <span className="text-[10px] font-bold text-slate-300 uppercase">Занято</span>
                )}
              </div>
            );
          })}
        </div>
      </div>
    );
  }

  // For owner or if no ownerWishlist, show nothing after started
  if (alreadyStarted) {
    return null;
  }

  // Legacy fallback UI (not used in current birthday flow)
  return (
    <div className="birthday-card confetti-fade px-6 py-6 text-center">
      <p className="text-xs uppercase text-pink-600 font-bold">Вы готовите сюрприз для</p>
      {!alreadyStarted && (
        <p className="mt-3 text-lg font-semibold text-slate-800">
          Скоро узнаем, чьи желания вам достались! 
        </p>
      )}
      {alreadyStarted && assignmentName && (
        <>
          <p className="mt-4 text-sm text-slate-600 font-medium">Именинник:</p>
          <p className="text-4xl font-black text-pink-600">{assignmentName}</p>
          <p className="mt-2 text-sm text-slate-600">
            Тссс! Это сюрприз, список видите только вы.
          </p>
          <div className="mt-6 text-left">
            <p className="text-xs uppercase tracking-[0.3em] text-cyan-400 font-bold">
              Список желаний:
            </p>
            {/* assignedWishlist removed */}
          </div>
        </>
      )}
      {alreadyStarted && !assignmentName && (
        <p className="mt-4 text-lg font-semibold text-slate-500">
          Мы обновляем данные, подождите секунду...
        </p>
      )}
    </div>
  );
}

import { Participant } from "@/types/secret-santa";

type Props = {
  participants: Participant[];
  highlightId?: string | null;
  ownerId?: string | null;
  showKickButton?: boolean;
  onKick?: (participantId: string) => void;
  busyId?: string | null;
};

export default function ParticipantsList({
  participants,
  highlightId,
  ownerId,
  showKickButton,
  onKick,
  busyId,
}: Props) {
  return (
    <div className="birthday-card px-6 py-5 text-slate-900">
      <div className="flex items-center justify-between">
        <h3 className="text-lg font-semibold">Список гостей</h3>
        <span className="text-xs uppercase tracking-[0.3em] text-pink-800 font-black">
          {participants.length}
        </span>
      </div>
      <ul className="mt-4 space-y-3 text-sm text-slate-900 font-bold">
        {participants.map((participant) => (
          <li
            key={participant.id}
            className={`flex items-center justify-between rounded-2xl border-2 border-black/5 px-4 py-2 transition hover:border-pink-300 ${
              participant.id === highlightId
                ? "bg-pink-50 text-pink-800 border-pink-200"
                : "bg-white"
            }`}
          >
            <span>{participant.name}</span>
            <div className="flex items-center gap-2">
              {participant.id === highlightId && (
                <span className="rounded-full bg-pink-500/20 px-3 py-1 text-xs uppercase text-pink-300 font-bold">
                  вы
                </span>
              )}
              {participant.id === ownerId && (
                <span className="rounded-full bg-amber-100 px-3 py-1 text-xs uppercase text-amber-700 font-bold">
                  именинник
                </span>
              )}
              {showKickButton &&
                onKick &&
                participant.id !== highlightId &&
                !busyId && (
                  <button
                    type="button"
                    onClick={() => onKick(participant.id)}
                    className="rounded-full border border-pink-200 px-3 py-1 text-xs uppercase text-pink-600 transition hover:bg-pink-50"
                  >
                    Удалить
                  </button>
                )}
              {showKickButton &&
                onKick &&
                participant.id !== highlightId &&
                busyId === participant.id && (
                  <span className="text-xs uppercase tracking-[0.3em] text-pink-600">
                    удаляем...
                  </span>
                )}
            </div>
          </li>
        ))}
      </ul>
      <p className="mt-3 text-xs text-slate-500">
        Редактировать список может только именинник.
      </p>
    </div>
  );
}

